<template>
	<view class="cont infocont">
		<!-- <view class="back-img" @click="$util.back()"></view> -->
		<u-modal v-model="upShow" class="addbank" title="选择提升等级" @confirm="uplevel" :show-cancel-button="true"
			:confirm-style="{color:'#e5cfb4',fontWeight:'600',border:'2rpx solid #f4f5f8'}">

			<u-form :model="form" ref="uForm" :label-width="140" label-align="center">
				<u-form-item label="等级">
					<u-input v-model="form.bankname" placeholder="请选择提升等级" :select-open="showbank" type="select"
						@click="showbank = true" />

				</u-form-item>
				<u-form-item label="金额">
					<u-input v-model="form.money" disabled />元
				</u-form-item>

			</u-form>
		</u-modal>
		<u-select v-model="showbank" :list="subjectList" @confirm="confirmBank"></u-select>
		<view class="">
			<view class="pad cont-top">
				<view class="cont-upgrade radius16">
					<view class="flex align-center">
						<image class="avatar round" :src="userinfo.headurl_img" mode="aspectFit"></image>
						<view class="flex-sub padding-left">
							<view class="text-lg">
								{{userinfo.company}}
							</view>
							<view class="text-sm padding-top-xs">
								当前等级：{{userinfo.level_name}}
							</view>
						</view>
						<view class="">
							<!-- <button class="cu-btn sm round" type="primary" v-if="subjectList.length >0"
								@click="upShow = true">立即升级</button> -->
							<button class="cu-btn sm round" type="primary" v-if="subjectList.length >0"
								@click="$util.on('/pages/ucenter_sub/upgrade/settle')">立即升级</button>
							<button class="cu-btn sm round" type="primary" v-if="subjectList.length ==0"
								disabled="">最高等级</button>
						</view>
					</view>
				</view>
				<view class="top-title text-bold margin-top flex align-center justify-center">
					<image class="icon-top" :src="$util.img('/statics/uni/img/upgrade/up_title_left.png')"
						mode="aspectFit"></image>
					<text>会员可享权益</text>
					<image class="icon-top" :src="$util.img('/statics/uni/img/upgrade/up_title_right.png')"
						mode="aspectFit"></image>
				</view>
				<view class="cont-grid flex flex-wrap align-center">

					<view class="item" v-for="(item,index) in quanyiList" :key="index" v-if="quanyiList.length >0">
						<view class="">
							<image class="img" :src="item.img" mode="aspectFit"></image>
						</view>
						<view class="item-bottom" style="color: #edc794;">
							{{item.title}}
						</view>

					</view>
				</view>
			</view>

			<view class="pad">
				<view class="tasktit flex align-end u-font-30 text-bold u-p-l-18 u-p-r-18">
					<text class="letter">UPGRADE</text>
					<text class="txt">做任务去升级</text>
				</view>
				<view class="cont-task radius16">
					<view class="item" v-for="(item,index) in taskList" :key="index" v-if="taskList.length >0">
						<view class="">
							<image class="img" :src="item.img" mode="aspectFit"></image>
						</view>
						<view class="item-right">
							<view class="right-title">
								<view class="title">
									{{item.title}}
								</view>
								<view class="desc">
									{{item.desc}}
								</view>
							</view>
							<view class="type" style="width: 160rpx;display: flex;
						align-items: center;
						justify-content: center;">
								<view class="type1" v-if="item.type == 1">
									{{item.data.start}}/{{item.data.end}}
								</view>
								<view class="type2" @click="showShare = true" v-if="item.type == 2 && !item.is_can">
									去分享
								</view>
								<view class="type2"
									style="  background: linear-gradient(90deg, #d0a060, #bb8b51);color: #fff ;"
									@click="uplevel(item.up_type)" v-if="item.is_can == 1">
									升级
								</view>
							</view>
						</view>

					</view>

					<u-empty v-if=" loaded && taskList.length == 0" margin-top="160" text="暂无任务"></u-empty>
				</view>


			</view>

		</view>


		<view class="cu-modal confirm">
			<view class="cu-dialog bg-white" style="width: 65%;">
				<view class="confirm-box">
					<view class="title padding-bottom-xs u-font-30">
						升级提示
					</view>
					<view class="u-font-26 text-gray666">
						您确定要升级到
						<text>等级1</text>
						？
					</view>
					<view class="flex align-center solid-top text-sm">
						<view class="flex-sub pad">
							取消
						</view>
						<view class="flex-sub pad solid-left text-infored">
							确定升级
						</view>
					</view>
				</view>
			</view>
		</view>

		<view class="cu-modal failbox" :style="{opacity:failboxShow?1:0}">
			<view class="cu-dialog" :style="{
				background: 'url('+$util.img('/statics/uni/img/upgrade/up_popup_bg.png')+') no-repeat',
				backgroundSize: '100% 100%'  
			}">
				<view class="box">
					<view class="text-lg text-bold">
						恭喜您
					</view>
					<view class="text-df padding-top-sm padding-bottom-xs">
						成功升级至 {{userinfo.level_name}}
					</view>
					<view class="">
						<image class="icon-vip" :src="$util.img('/statics/uni/img/upgrade/up_popup_vip.png')"
							mode="aspectFit"></image>
					</view>
				</view>
				<view class="flex align-center text-sm" @click="failboxShow = false" style="pointer-events: auto;">
					<button class="cu-btn upbtn">确定</button>
				</view>
			</view>
		</view>
		<view class="cu-modal successbox">
			<view class="cu-dialog bg-white" style="width: 70%;">
				<view class="box">
					<view class="text-lg text-bold">
						很遗憾
					</view>
					<view class="text-df padding-top-sm">
						您目前暂时还未达到升级条件
					</view>
					<view class="">
						<image class="icon-vip" :src="$util.img('/statics/uni/img/upgrade/up_popup_vip.png')"
							mode="aspectFit"></image>
					</view>
				</view>
				<view class="flex align-center text-sm">
					<button class="cu-btn upbtn">做任务去升级</button>

				</view>
			</view>
		</view>



		<u-popup v-model="showShare" mode="bottom" class="share-popup"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20">


			<view class="popup-content">

				<view class="share-title">
					<view class="title">
						{{sharetitle}}
					</view>

				</view>
				<view class="share-box">
					<view class="share-item" v-for="(item,index) in shareList" :key="index" @click="clickShare(item)">
						<image class="img" :src="item.img" mode="aspectFit"></image>
						<view class="text">
							{{item.title}}
						</view>
					</view>
				</view>

				<view class="close">
					<view @click="showShare = false">取消</view>
				</view>
			</view>
		</u-popup>
		<u-modal v-model="showShareCopy" @confirm="clickShareCopy" ref="showShareCopy_box" :async-close="true"
			:show-cancel-button="true" :title="'专属链接'" :confirm-text="'复制'" :confirm-style="{
			color:'#e5cfb4',
			fontWeight:600,
			border:'2rpx solid #f4f5f8',
		}">
			<view class="slot-content">
				<view class="copy-box">
					<swiper :current="current" @change="changeswiper">
						<swiper-item class="swiper-item" v-for="(item, index) in shareCopyList" :key="index">
							<view class="view-box">
								<text class="text">
									{{item.title}}
								</text>
							</view>
						</swiper-item>
					</swiper>
					<view class="swiper-left" v-if="current>0" @click="clickSwiperLeft">
						<u-icon size="40" name="arrow-left"></u-icon>
					</view>
					<view class="swiper-right" v-if="current < shareCopyList.length -1" @click="clickSwiperRight">
						<u-icon size="40" name="arrow-right"></u-icon>
					</view>
				</view>
			</view>
		</u-modal>
		<pointShare :show="pointShareShow" @close="pointShareShow =false"></pointShare>
	</view>
</template>


<script>
	import md5Libs from "uview-ui/libs/function/md5";
	import pointShare from '@/components/point-share/index.vue'

	export default {
		components: {
			pointShare
		},
		data() {
			return {
				action: '', //上传图片方法
				sys: this.$util.sys(),
				page: 1,
				limit: 10,
				ordersn: '',
				subject: '',
				subjectList: [

				],
				complainList: [],
				show: false,
				content: '',
				screenshot: '',
				header: {
					token: '',
					sign: '',
				},

				is_have_complain: true,
				money: '0.00',
				rangeLevel: [],
				grade: 0,


				quanyiList: [],
				taskList: [],

				failboxShow: false,
				upShow: false,



				showform: false,
				showbank: false,
				form: {
					bank: 0,
					bankname: '',
					money: '0.00',
				},
				bankList: [],
				bankSelect: [],
				showdraw: false,
				loaded: false,


				pointShareShow: false,
				showShare: false,
				shareList: [],
				shareCopyList: [],
				sharetitle: '',
				showShareCopy: false,
				current: 0,
				upgradeitem: {
					yq_one: 0,
					yj_up_day: 0,
					yj_up: 0,
				},
			}
		},


		onLoad(e) {


			this.loadData();

		},

		methods: {
			confirmBank(e) {
				const {
					amount,
					label,
					value
				} = this.rangeLevel.find(item => item.value == e[0].value)
				this.form.bank = value
				this.form.bankname = label
				this.form.money = amount

			},
			previewImage(url) { // index 索引 如果 需要复用方法 可以使用 类型来进行区分(val)

				uni.previewImage({
					current: 0, // 当前显示图片的索引值
					urls: [url], // 需要预览的图片列表，photoList要求必须是数组

				})
			},


			async loadData() {
				// this.loading = true;
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				// let params = {};
				await this.$u.api.upgradeConfig({

					})
					.then(res => {



						this.$u.vuex('userinfo.level_id', res.userinfo.level_id);
						this.$u.vuex('userinfo.level_name', res.userinfo.level_name);
						this.rangeLevel = res.rangeLevel
						this.subjectList = res.rangeLevel




						if (this.subjectList.length > 0) {
							this.form.bank = res.rangeLevel[0].value
							this.form.bankname = this.subjectList[0].label
							this.form.money = res.rangeLevel[0].amount
							this.upgradeitem = this.rangeLevel[0]

							// this.subject = this.subjectList[0].label
							// this.money = res.rangeLevel[0].upgradefee
						}


						this.taskList = res.taskList
						this.quanyiList = res.quanyiList

						this.loaded = true;


						this.shareList = res.shareList
						this.sharetitle = res.sharetitle

						//#ifdef H5
						if (this.$util.browserType('weixin')) {
							this.wxShare(res.sharewxgzhConfig, {
								title: '分享',
								desc: '分享',
								linkUrl: linkUrl + '&pid=' + this.userinfo.id,
								imgUrl: '',
							})
						}
						//#endif

					}).catch(res => {})

				// this.loading = false;
				uni.hideLoading()

			},
			confirm(e) {
				this.subject = e[0].label
				this.grade = e[0].value
			},
			//升级
			async uplevel(up_type) {


				if (!up_type) {
					if (this.form.bank == 0) {
						this.$util.msg('请选择提升等级');
						return;
					}
				}




				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				await this.$u.api.upgrade({
						grade: this.form.bank,
						type: up_type,

					})
					.then(res => {
						this.$util.msg('自助升级成功');
						this.loadData()

						this.failboxShow = true
					}).catch(res => {})
				uni.hideLoading()

			},

			clickSwiperLeft() {
				if (this.current > 0) {
					this.current--
				}
			},
			//分享
			share() {
				this.$util.on('/pages/common/poster?share_from=2&pid=' + this.userinfo.id);
			},
			clickSwiperRight() {
				if (this.current < this.shareCopyList.length - 1) {
					this.current++
				}
			},
			changeswiper(e) {
				this.current = e.detail.current
			},
			clickShareCopy() {


				uni.setClipboardData({
					data: this.shareCopyList[this.current].title + this.shareCopyList[this.current].url,
					success: function() {
						uni.showToast({
							title: '复制链接成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}

				})

				this.$refs.showShareCopy_box.clearLoading()
				this.showShareCopy = false
			},


			async wxShare(res, options) {


				//配置
				jWeixin.config({
					debug: res.debug ? true : false, //根据服务端来控制是否开启调试模式
					appId: res.appId,
					timestamp: res.timestamp,
					nonceStr: res.nonceStr,
					signature: res.signature,
					jsApiList: res.jsApiList,
				});
				//分享的触发动作必须写再ready里面
				jWeixin.ready(() => {
					//配置分享数据
					let shareData = {
						title: options.title || "", //分享的标题
						desc: options.desc || "", //分享的描述
						link: options.linkUrl, //分享的链接
						imgUrl: options.imgUrl || "", //分享的图片链接
						success(response) {
							//配置成功之后的回调（并不是分享成功之后的回调，这个地方是个坑，要注意下）
							// console.log('user shared');
						},
					};
					jWeixin.updateAppMessageShareData(shareData);
					jWeixin.updateTimelineShareData(shareData);
					jWeixin.onMenuShareAppMessage(shareData);
					jWeixin.onMenuShareTimeline(shareData);
				});




			},
			async clickShare(item) {
				switch (item.type) {
					case 'weixin':

						//#ifdef H5

						//微信浏览器
						if (this.$util.browserType('weixin')) {
							//微信指引
							this.pointShareShow = true
							this.showShare = false



						} else {
							// this.pointShareShow = true
							// this.showShare = false




						}

						//#endif



						break;
					case 'link':
						this.shareCopyList = item.linkList
						this.showShareCopy = true
						this.showShare = false;
						break;
					case 'img':
						this.share()
						break;
				}

			},





		}

	}
</script>
